const SOCCER_TEAMMATE_PAIRS: ReadonlySet<string> = new Set(SOCCER_TEAMMATE_PAIR_KEYS);

function pairKey(a: string, b: string): string {
  return JSON.stringify([a, b].sort());
}

export function areSoccerTeammates(identityA: string, identityB: string): boolean {
  return identityA !== identityB && SOCCER_TEAMMATE_PAIRS.has(pairKey(identityA, identityB));
}
